import React, { useState, useEffect } from 'react';
import { Search, CloudUpload, Trash2, Loader2, AlertCircle, AlertTriangle, CheckCircle2, Building2, UserX, Ticket } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { db } from '../services/db';
import { UserRole, TicketStatus } from '../types';

const Stock: React.FC = () => {
  const navigate = useNavigate();
  const [filter, setFilter] = useState<'TOUS' | 'NEUF' | 'VENDU'>('TOUS');
  const [agencyFilter, setAgencyFilter] = useState<string>('ALL');
  const [search, setSearch] = useState('');
  const [tickets, setTickets] = useState<any[]>([]);
  const [agencies, setAgencies] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [ticketToDelete, setTicketToDelete] = useState<any | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);
  const [ticketToUnassign, setTicketToUnassign] = useState<any | null>(null);
  const [isUnassigning, setIsUnassigning] = useState(false);
  const [toast, setToast] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  useEffect(() => { fetchInitialData(); }, []);
  useEffect(() => { fetchStock(); }, [filter, search, agencyFilter, currentUser]);

  const fetchInitialData = async () => {
    try {
      const { data: { user } } = await db.auth.getUser();
      if (user) {
        const { data: userData } = await db.from('users').select('role, tenant_id, id').eq('id', user.id).single();
        if (userData) {
          setCurrentUser(userData);
          if (userData.role === UserRole.ADMIN_GLOBAL) {
            const { data: tData } = await db.from('tenants').select('id, name').order('name');
            setAgencies(tData || []);
          }
        }
      }
    } catch (err) { console.error(err); }
  };

  const fetchStock = async () => {
    if (!currentUser) return;
    try {
      setLoading(true);
      let query = db.from('tickets')
        .select(`id, username, password, status, imported_at, assigned_to, tenants(name), ticket_profiles(name, price), users!tickets_assigned_to_fkey(full_name)`)
        .order('imported_at', { ascending: false });

      const isReseller = currentUser.role === UserRole.REVENDEUR;

      if (currentUser.role === UserRole.ADMIN_GLOBAL) { 
        if (agencyFilter !== 'ALL') query = query.eq('tenant_id', agencyFilter); 
      } else { 
        query = query.eq('tenant_id', currentUser.tenant_id); 
      }

      if (isReseller) {
         query = query.eq('assigned_to', currentUser.id);
      }

      if (filter !== 'TOUS') {
          if (isReseller && filter === 'NEUF') {
              query = query.eq('status', TicketStatus.ASSIGNE);
          } else {
              query = query.eq('status', filter);
          }
      }

      if (search) query = query.ilike('username', `%${search}%`);

      const { data, error: tError } = await query.limit(300);
      if (tError) throw tError;
      setTickets(data || []);
    } catch (err: any) { showToast('error', err.message); } finally { setLoading(false); }
  };

  const showToast = (type: 'success' | 'error', message: string) => { setToast({ type, message }); setTimeout(() => setToast(null), 3000); };

  const handleVerifyDelete = (ticket: any) => { 
    if (currentUser?.role === UserRole.REVENDEUR) { showToast('error', "Action refusée."); return; } 
    if (ticket.status !== TicketStatus.NEUF) { showToast('error', "Impossible de supprimer un ticket vendu ou assigné."); return; } 
    setTicketToDelete(ticket); 
  };

  const performDelete = async () => { 
    if (!ticketToDelete) return; 
    setIsDeleting(true); 
    try { 
        const { error: dError } = await db.from('tickets').delete().eq('id', ticketToDelete.id); 
        if (dError) throw dError; 
        setTickets(prev => prev.filter(t => t.id !== ticketToDelete.id)); 
        showToast('success', `Ticket supprimé.`); 
        setTicketToDelete(null); 
    } catch (err: any) { showToast('error', err.message); } finally { setIsDeleting(false); } 
  };

  const handleVerifyUnassign = (ticket: any) => {
    if (currentUser?.role === UserRole.REVENDEUR) return;
    setTicketToUnassign(ticket);
  };

  const performUnassign = async () => {
    if (!ticketToUnassign) return;
    setIsUnassigning(true);
    try {
        const { error } = await db.from('tickets').update({ status: TicketStatus.NEUF, assigned_to: null }).eq('id', ticketToUnassign.id);
        if (error) throw error;
        setTickets(prev => prev.map(t => {
            if (t.id === ticketToUnassign.id) return { ...t, status: TicketStatus.NEUF, assigned_to: null, users: null };
            return t;
        }));
        showToast('success', "Ticket retiré du revendeur."); setTicketToUnassign(null);
    } catch (err: any) { showToast('error', err.message); } finally { setIsUnassigning(false); }
  };

  const isReseller = currentUser?.role === UserRole.REVENDEUR;

  return (
    <div className="space-y-6 md:space-y-8 font-sans pb-24 animate-in fade-in duration-500 relative">
      {toast && (<div className={`fixed top-6 right-6 z-[60] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right-10 border ${toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-red-600 text-white border-red-500'}`}>{toast.type === 'success' ? <CheckCircle2 className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}<p className="font-bold text-sm">{toast.message}</p></div>)}

      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
          <div>
              <span className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-1 block">{currentUser?.role === UserRole.ADMIN_GLOBAL ? 'SUPERVISION GLOBALE DES STOCKS' : (isReseller ? 'MON STOCK PERSONNEL' : 'INVENTAIRE AGENCE')}</span>
              <h1 className="text-3xl md:text-4xl font-black text-[#1e293b] tracking-tight">Gestion Stock</h1>
          </div>
          {currentUser?.role === UserRole.GESTIONNAIRE_WIFI_ZONE && (
              <button onClick={() => navigate('/import')} className="bg-slate-900 text-white px-6 py-4 rounded-2xl font-black text-xs tracking-widest uppercase shadow-xl flex items-center justify-center gap-3 hover:bg-black transition-all active:scale-95 w-full lg:w-auto">
                  <CloudUpload className="w-4 h-4" /> IMPORTER CSV
              </button>
          )}
      </div>

      <div className="bg-white rounded-[2rem] md:rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-6 md:p-8 space-y-6">
              <div className="flex flex-col md:flex-row gap-4">
                  <div className="relative group flex-1">
                      <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-indigo-500 transition-colors" />
                      <input type="text" placeholder="Rechercher par code..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full pl-14 pr-8 py-4 rounded-2xl border border-slate-100 bg-slate-50/30 focus:bg-white focus:ring-4 focus:ring-indigo-50 outline-none font-bold text-slate-600 transition-all text-sm md:text-base" />
                  </div>
                  {currentUser?.role === UserRole.ADMIN_GLOBAL && (
                      <div className="relative w-full md:w-64">
                          <Building2 className="absolute left-5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
                          <select value={agencyFilter} onChange={(e) => setAgencyFilter(e.target.value)} className="w-full pl-12 pr-6 py-4 rounded-2xl border border-slate-100 bg-slate-50 font-bold text-slate-600 appearance-none outline-none focus:ring-4 focus:ring-indigo-50 transition-all text-sm"><option value="ALL">Toutes les agences</option>{agencies.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}</select>
                      </div>
                  )}
              </div>

              <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                  {(['TOUS', 'NEUF', 'VENDU'] as const).map((f) => (
                      <button key={f} onClick={() => setFilter(f)} className={`px-5 py-2.5 rounded-xl font-black text-[10px] tracking-widest uppercase transition-all whitespace-nowrap ${filter === f ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-white border border-slate-100 text-slate-400 hover:text-slate-600'}`}>
                          {f === 'NEUF' ? 'STOCK DISPO' : f}
                      </button>
                  ))}
              </div>
          </div>

          <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[800px]">
                  <thead>
                      <tr className="border-y border-slate-50 bg-slate-50/30 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                          {!isReseller && <th className="px-6 md:px-8 py-4">CODE</th>}
                          {(currentUser?.role === UserRole.ADMIN_GLOBAL || agencyFilter === 'ALL') && <th className="px-6 md:px-8 py-4">AGENCE</th>}
                          <th className="px-6 md:px-8 py-4">PROFIL</th>
                          <th className="px-6 md:px-8 py-4 text-right">PRIX</th>
                          <th className="px-6 md:px-8 py-4 text-center">STATUT</th>
                          {currentUser?.role !== UserRole.REVENDEUR && currentUser?.role !== UserRole.ADMIN_GLOBAL && <th className="px-6 md:px-8 py-4 text-right">ACTIONS</th>}
                      </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                      {loading ? (<tr><td colSpan={6} className="px-8 py-20 text-center"><Loader2 className="w-8 h-8 animate-spin mx-auto text-indigo-200" /></td></tr>) : tickets.length === 0 ? (<tr><td colSpan={6} className="px-8 py-20 text-center text-slate-300 font-bold uppercase text-xs">Aucun ticket</td></tr>) : tickets.map((item) => {
                          let statusLabel = 'VENDU';
                          let statusColor = 'bg-emerald-50 text-emerald-500';
                          if (item.status === TicketStatus.NEUF) { statusLabel = 'EN STOCK'; statusColor = 'bg-indigo-50 text-indigo-500'; }
                          else if (item.status === TicketStatus.ASSIGNE) { if (isReseller) { statusLabel = 'EN STOCK'; statusColor = 'bg-indigo-50 text-indigo-500'; } else { statusLabel = `CHEZ ${item.users?.full_name?.split(' ')[0] || 'REVENDEUR'}`; statusColor = 'bg-purple-50 text-purple-600'; } }
                          return (
                            <tr key={item.id} className="hover:bg-slate-50/50 transition-colors group">
                                {!isReseller && <td className="px-6 md:px-8 py-6 font-black text-slate-900 tracking-tight">{item.username}</td>}
                                {(currentUser?.role === UserRole.ADMIN_GLOBAL || agencyFilter === 'ALL') && (<td className="px-6 md:px-8 py-6"><div className="flex items-center gap-2"><Building2 className="w-3 h-3 text-slate-300" /><span className="text-[10px] font-black text-slate-500 uppercase">{item.tenants?.name}</span></div></td>)}
                                <td className="px-6 md:px-8 py-6 font-black text-xs text-indigo-500 uppercase">{item.ticket_profiles?.name}</td>
                                <td className="px-6 md:px-8 py-6 font-black text-slate-900 text-right">{Number(item.ticket_profiles?.price).toLocaleString()} GNF</td>
                                <td className="px-6 md:px-8 py-6 text-center"><span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${statusColor} whitespace-nowrap`}>{statusLabel}</span></td>
                                {currentUser?.role !== UserRole.REVENDEUR && currentUser?.role !== UserRole.ADMIN_GLOBAL && (
                                    <td className="px-6 md:px-8 py-6 text-right">
                                        {item.status === TicketStatus.ASSIGNE ? (
                                            <button onClick={() => handleVerifyUnassign(item)} title="Retirer" className="p-2 rounded-lg transition-all text-orange-400 hover:text-orange-600 hover:bg-orange-50 bg-white shadow-sm border border-slate-100"><UserX className="w-4 h-4" /></button>
                                        ) : (
                                            <button onClick={() => handleVerifyDelete(item)} disabled={item.status === TicketStatus.VENDU} className={`p-2 rounded-lg transition-all ${(item.status === TicketStatus.VENDU) ? 'text-slate-100 opacity-20' : 'text-slate-300 hover:text-red-600 hover:bg-red-50'}`}><Trash2 className="w-4 h-4" /></button>
                                        )}
                                    </td>
                                )}
                            </tr>
                          );
                      })}
                  </tbody>
              </table>
          </div>
      </div>

      {/* Modal Suppression */}
      {ticketToDelete && (<div className="fixed inset-0 z-50 flex items-center justify-center p-4"><div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => !isDeleting && setTicketToDelete(null)} /><div className="bg-white w-full max-w-sm rounded-[3rem] p-10 text-center relative z-10 animate-in zoom-in-95 shadow-2xl"><div className="w-20 h-20 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-6"><AlertTriangle className="w-10 h-10" /></div><h3 className="text-2xl font-black text-slate-900 mb-2 uppercase">Supprimer ?</h3><p className="text-slate-500 text-sm mb-8">Action irréversible sur le ticket <strong>{ticketToDelete.username}</strong>.</p><div className="space-y-3"><button onClick={performDelete} disabled={isDeleting} className="w-full py-5 bg-red-600 text-white rounded-2xl font-black text-xs uppercase shadow-xl hover:bg-red-700">{isDeleting ? <Loader2 className="w-5 h-5 animate-spin mx-auto" /> : "OUI, SUPPRIMER"}</button><button onClick={() => setTicketToDelete(null)} className="w-full py-5 bg-slate-100 text-slate-400 rounded-2xl font-black text-xs uppercase">ANNULER</button></div></div></div>)}

      {/* Modal Désassignation */}
      {ticketToUnassign && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => !isUnassigning && setTicketToUnassign(null)} />
              <div className="bg-white w-full max-w-sm rounded-[3rem] p-10 text-center relative z-10 animate-in zoom-in-95 shadow-2xl">
                  <div className="w-20 h-20 bg-orange-50 text-orange-500 rounded-full flex items-center justify-center mx-auto mb-6"><UserX className="w-10 h-10" /></div>
                  <h3 className="text-2xl font-black text-slate-900 mb-2 uppercase">Retirer Ticket ?</h3>
                  <p className="text-slate-500 text-sm mb-4 leading-relaxed">Le ticket <strong>{ticketToUnassign.username}</strong> sera retiré du revendeur <span className="text-slate-900 font-bold">{ticketToUnassign.users?.full_name}</span>.</p>
                  <p className="text-xs font-bold text-emerald-600 bg-emerald-50 py-2 px-4 rounded-xl mb-8">Il retournera dans votre stock principal (Statut: NEUF).</p>
                  <div className="space-y-3"><button onClick={performUnassign} disabled={isUnassigning} className="w-full py-5 bg-orange-500 text-white rounded-2xl font-black text-xs uppercase shadow-xl hover:bg-orange-600 transition-all active:scale-95 flex items-center justify-center gap-2">{isUnassigning ? <Loader2 className="w-5 h-5 animate-spin" /> : "CONFIRMER LE RETRAIT"}</button><button onClick={() => setTicketToUnassign(null)} disabled={isUnassigning} className="w-full py-5 bg-slate-100 text-slate-400 rounded-2xl font-black text-xs uppercase hover:bg-slate-200 transition-all">ANNULER</button></div>
              </div>
          </div>
      )}
    </div>
  );
};
export default Stock;

import React, { useState, useEffect, useCallback } from 'react';
import { db } from '../services/db';
import { History as HistoryIcon, Search, Loader2, Info, X, QrCode, Share2, RefreshCcw, RotateCcw, AlertTriangle, CheckCircle2, Building2, Calendar, AlertCircle, Printer, Filter } from 'lucide-react';
import { UserRole, Sale } from '../types';

const History: React.FC = () => {
  const [sales, setSales] = useState<Sale[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [agencyFilter, setAgencyFilter] = useState<string>('ALL');
  const [agencies, setAgencies] = useState<any[]>([]);
  const [stats, setStats] = useState({ totalCount: 0, totalRevenue: 0 });
  const [toast, setToast] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const [currentUser, setCurrentUser] = useState<{ id: string, role: UserRole, tenant_id?: string, tenantName?: string } | null>(null);
  const [selectedSale, setSelectedSale] = useState<Sale | null>(null);
  const [saleToCancel, setSaleToCancel] = useState<Sale | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const notify = useCallback((type: 'success' | 'error', message: string) => { setToast({ type, message }); setTimeout(() => setToast(null), 4000); }, []);
  useEffect(() => { fetchInitialContext(); }, []);
  useEffect(() => { fetchHistory(); }, [agencyFilter, searchTerm, currentUser]);

  const fetchInitialContext = async () => {
    try {
      const { data: { user } } = await db.auth.getUser();
      if (!user) return;
      const { data: userData } = await db.from('users').select('role, tenant_id, tenants(name)').eq('id', user.id).single();
      const currentRole = userData?.role as UserRole;
      const tenantName = (userData?.tenants as any)?.name;
      setCurrentUser({ id: user.id, role: currentRole, tenant_id: userData?.tenant_id, tenantName });
      if (currentRole === UserRole.ADMIN_GLOBAL) { const { data: tData } = await db.from('tenants').select('id, name').order('name'); setAgencies(tData || []); }
    } catch (err) { console.error(err); }
  };

  const fetchHistory = async () => {
    if (!currentUser) return;
    try {
      setLoading(true);
      let query = db.from('sales_history').select(`id, amount_paid, sold_at, metadata, ticket_id, tenant_id, seller_id, tenants(name), tickets(id, username, password, status, ticket_profiles(name)), users(full_name)`);
      if (currentUser.role === UserRole.REVENDEUR) query = query.eq('seller_id', currentUser.id);
      else if (currentUser.role === UserRole.ADMIN_GLOBAL) { if (agencyFilter !== 'ALL') query = query.eq('tenant_id', agencyFilter); } else query = query.eq('tenant_id', currentUser.tenant_id);
      if (searchTerm) query = query.ilike('tickets.username', `%${searchTerm}%`);
      const { data, error } = await query.order('sold_at', { ascending: false }).limit(500);
      if (error) throw error;
      const results = (data as unknown as Sale[]) || [];
      setSales(results);
      setStats({ totalCount: results.length, totalRevenue: results.reduce((acc, curr) => acc + Number(curr.amount_paid), 0) });
    } catch (err: any) { console.error("History fetch error:", err); } finally { setLoading(false); }
  };

  const handlePrint = () => { window.print(); };
  const initiateCancellation = (sale: Sale) => { if (!currentUser) return; const canCancel = currentUser.role === UserRole.ADMIN_GLOBAL || currentUser.role === UserRole.GESTIONNAIRE_WIFI_ZONE || (currentUser.role === UserRole.REVENDEUR && sale.seller_id === currentUser.id); if (!canCancel) { notify('error', "Accès refusé."); return; } setSaleToCancel(sale); };
  const confirmCancellation = async () => { if (!saleToCancel) return; setIsProcessing(true); const targetTicketId = saleToCancel.ticket_id || saleToCancel.tickets?.id; try { const { data: sellerProfile } = await db.from('users').select('role, balance').eq('id', saleToCancel.seller_id).single(); if (sellerProfile?.role === UserRole.REVENDEUR) await db.from('users').update({ balance: Number(sellerProfile.balance || 0) + Number(saleToCancel.amount_paid) }).eq('id', saleToCancel.seller_id); await db.from('tickets').update({ status: 'NEUF', sold_at: null, sold_by: null, assigned_to: null }).eq('id', targetTicketId); await db.from('sales_history').delete().eq('id', saleToCancel.id); notify('success', "Vente annulée."); setSaleToCancel(null); setSelectedSale(null); await fetchHistory(); } catch (err: any) { notify('error', "Échec : " + err.message); } finally { setIsProcessing(false); } };
  const handleWhatsAppShare = () => { if (!selectedSale) return; window.open(`https://wa.me/?text=${encodeURIComponent(`*TICKET WIFI*\n\n🎟️ CODE : *${selectedSale.tickets?.username}*\n📦 FORFAIT : ${selectedSale.tickets?.ticket_profiles?.name}\n💰 PRIX : ${Number(selectedSale.amount_paid).toLocaleString()} GNF\n\nMerci !`)}`, '_blank'); };
  const filteredSales = sales.filter(sale => { const s = searchTerm.toLowerCase(); return sale.tickets?.username?.toLowerCase().includes(s) || sale.users?.full_name?.toLowerCase().includes(s); });

  return (
    <div className="space-y-6 font-sans pb-24 animate-in fade-in duration-500 relative">
      {toast && (<div className={`fixed top-6 right-6 z-[100] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right border ${toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-red-600 text-white border-red-500'}`}>{toast.type === 'success' ? <CheckCircle2 className="w-5 h-5 shrink-0" /> : <AlertCircle className="w-5 h-5 shrink-0" />}<p className="font-bold text-sm tracking-tight">{toast.message}</p></div>)}

      <div className="bg-white p-6 md:p-10 rounded-[2.5rem] md:rounded-[3rem] border border-slate-100 shadow-sm flex flex-col md:flex-row items-start md:items-center justify-between gap-8 relative overflow-hidden">
          {currentUser?.role === UserRole.ADMIN_GLOBAL && (<div className="absolute top-0 right-0 w-64 h-64 bg-brand-500/5 rounded-full blur-[80px] -mr-20 -mt-20"></div>)}
          <div className="flex items-center gap-5 relative z-10">
              <div className={`w-14 h-14 md:w-16 md:h-16 rounded-2xl flex items-center justify-center shadow-2xl ${currentUser?.role === UserRole.ADMIN_GLOBAL ? 'bg-brand-600 text-white' : 'bg-slate-900 text-white'}`}>
                  <HistoryIcon className="w-7 h-7 md:w-8 md:h-8" />
              </div>
              <div>
                  <div className="flex items-center gap-2 mb-1">
