                 VENDRE <ArrowRight className="w-5 h-5" />
             </button>
          </div>
        )) : (
            <div className="col-span-full py-40 text-center">
                <div className="w-20 h-20 bg-slate-50 text-slate-200 rounded-full flex items-center justify-center mx-auto mb-6">
