{p.name}</h3><p className="text-2xl font-black text-brand-600 mb-6">{p.price.toLocaleString()} <span className="text-[10px] uppercase">{currency}</span></p><div className="pt-6 border-t border-slate-100 flex items-center justify-between"><div className="flex flex-col"><span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">En Stock</span><span className={`text-sm font-black ${p.tickets?.[0]?.count < 20 ? 'text-red-500' : 'text-slate-900'}`}>{p.tickets?.[0]?.count || 0} pcs</span></div><div className="h-1.5 w-24 bg-slate-100 rounded-full overflow-hidden"><div className={`h-full rounded-full ${p.tickets?.[0]?.count < 20 ? 'bg-red-500' : 'bg-brand-500'}`} style={{ width: `${Math.min(100, ((p.tickets?.[0]?.count || 0) / 100) * 100)}%` }} /></div></div></div>)) : (<div className="col-span-full py-20 text-center text-slate-300 font-bold uppercase text-xs">Aucun forfait configuré</div>)}</div></div>
