import React, { useState, useEffect } from 'react';
import { Save, Smartphone, Phone, Banknote, Trash2, Zap, Users, Store, Loader2, Building2, Sparkles, Server, Activity, Database, UserCircle, KeyRound, Lock, LogOut, ShieldCheck, Clock, CheckCircle2, AlertTriangle, ToggleLeft, ToggleRight, Settings as SettingsIcon } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { db } from '../services/db';
import { UserRole } from '../types';

const Settings: React.FC = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [userProfile, setUserProfile] = useState<any>(null);
  const [activeTab, setActiveTab] = useState<'PROFILE' | 'AGENCY'>('PROFILE');
  const [profileForm, setProfileForm] = useState({ fullName: '', currentPassword: '', newPassword: '', confirmPassword: '' });
  const [stockCount, setStockCount] = useState(0);
  const [expiredCount, setExpiredCount] = useState(0);
  const [agencyForm, setAgencyForm] = useState({ whatsappHeader: 'Bienvenue sur notre réseau WiFi', contactSupport: '', currency: 'GNF' });
  const [saasStats, setSaasStats] = useState({ totalTenants: 0, totalUsers: 0, systemHealth: 'Optimal (Local)', dbLatency: '0ms' });
  const [toast, setToast] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const [saasConfig, setSaasConfig] = useState({ id: '', monthly_subscription_price: 150000, trial_period_days: 30, support_phone_number: '', is_maintenance_mode: false });

  useEffect(() => { fetchSettings(); }, []);

  const showToast = (type: 'success' | 'error', message: string) => { setToast({ type, message }); setTimeout(() => setToast(null), 4000); };

  const fetchSettings = async () => {
    try {
      setLoading(true);
      const { data: { user } } = await db.auth.getUser();
      if (!user) return;
      const { data: profile } = await db.from('users').select('*, tenants(name, id, currency)').eq('id', user.id).single();
      if (profile) {
        setUserProfile(profile); setProfileForm(prev => ({ ...prev, fullName: profile.full_name || '' }));

        if (profile.role === UserRole.ADMIN_GLOBAL) {
          const { count: tenantsCount } = await db.from('tenants').select('*', { count: 'exact', head: true });
          const { count: usersCount } = await db.from('users').select('*', { count: 'exact', head: true });
          setSaasStats(prev => ({ ...prev, totalTenants: tenantsCount || 0, totalUsers: usersCount || 0 }));

          const { data: config } = await db.from('saas_settings').select('*').maybeSingle();
          if (config) setSaasConfig(config);

        } else if (profile.tenant_id) {
          const { count } = await db.from('tickets').select('*', { count: 'exact', head: true }).eq('tenant_id', profile.tenant_id); setStockCount(count || 0);
          const { count: expired } = await db.from('tickets').select('*', { count: 'exact', head: true }).eq('tenant_id', profile.tenant_id).eq('status', 'EXPIRE'); setExpiredCount(expired || 0);

          // Load currency
          const currentCurrency = (profile.tenants as any)?.currency || 'GNF';
          setAgencyForm(prev => ({...prev, contactSupport: user.email || '', currency: currentCurrency }));
        }
      }
    } catch (err) { console.error(err); } finally { setLoading(false); }
  };

  const handleUpdateProfile = async (e: React.FormEvent) => {
    e.preventDefault(); setSaving(true);
    try {
      if (profileForm.fullName !== userProfile.full_name) await db.from('users').update({ full_name: profileForm.fullName }).eq('id', userProfile.id);
      if (profileForm.newPassword) { if (profileForm.newPassword !== profileForm.confirmPassword) throw new Error("Les mots de passe ne correspondent pas."); await db.auth.updateUser({ password: profileForm.newPassword }); }
      showToast('success', "Profil mis à jour avec succès !"); setProfileForm(p => ({ ...p, newPassword: '', confirmPassword: '' })); fetchSettings();
    } catch (err: any) { showToast('error', "Erreur : " + err.message); } finally { setSaving(false); }
  };

  const handleSaveAgency = async () => { 
      setSaving(true); 
      try {
          if (userProfile?.tenant_id) {
              const { error } = await db.from('tenants').update({ currency: agencyForm.currency, whatsappHeader: agencyForm.whatsappHeader }).eq('id', userProfile.tenant_id);
              if (error) throw error;
              showToast('success', "Configuration et devise sauvegardées !"); 
          }
      } catch(err: any) {
          showToast('error', "Erreur sauvegarde: " + err.message);
      } finally {
          setSaving(false); 
      }
  };

  const handleCleanExpired = async () => { if (!userProfile?.tenant_id || !confirm("Supprimer les tickets expirés ?")) return; await db.from('tickets').delete().eq('tenant_id', userProfile.tenant_id).eq('status', 'EXPIRE'); showToast('success', "Nettoyage effectué !"); setExpiredCount(0); fetchSettings(); };

  const handleSaveSaasConfig = async () => {
    if (!confirm("ACTION CRITIQUE : Confirmez-vous la mise à jour des paramètres globaux ?")) return;
    setSaving(true);
    try {
        const payload = {
            monthly_subscription_price: saasConfig.monthly_subscription_price,
            trial_period_days: saasConfig.trial_period_days,
            support_phone_number: saasConfig.support_phone_number,
            is_maintenance_mode: saasConfig.is_maintenance_mode,
            updated_at: new Date().toISOString()
        };
        if (saasConfig.id) await db.from('saas_settings').update(payload).eq('id', saasConfig.id);
        else await db.from('saas_settings').insert(payload);
        showToast('success', "Configuration SaaS mise à jour."); await fetchSettings();
    } catch (err: any) { showToast('error', "Erreur : " + err.message); } finally { setSaving(false); }
  };

  const handleLogout = async () => { await db.auth.signOut(); navigate('/'); };

  if (loading) return <div className="flex items-center justify-center h-96"><Loader2 className="w-8 h-8 text-brand-600 animate-spin" /></div>;

  return (
    <div className="space-y-8 font-sans pb-20 animate-in fade-in duration-500 relative">
      {toast && (<div className={`fixed top-6 right-6 z-[100] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right-10 border ${toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-red-600 text-white border-red-500'}`}>{toast.type === 'success' ? <CheckCircle2 className="w-5 h-5" /> : <AlertTriangle className="w-5 h-5" />}<p className="font-bold text-sm tracking-tight">{toast.message}</p></div>)}

      {userProfile?.role === UserRole.ADMIN_GLOBAL ? (
        <div className="space-y-12">
            <div className="bg-[#1e293b] p-10 rounded-[3rem] shadow-2xl relative overflow-hidden flex flex-col md:flex-row md:items-center justify-between gap-8">
                <div className="absolute top-0 right-0 w-80 h-80 bg-brand-500 rounded-full blur-[120px] opacity-20 -mr-20 -mt-20"></div>
                <div className="relative z-10 flex items-center gap-6">
                    <div className="w-20 h-20 bg-white/10 backdrop-blur-sm rounded-[2rem] flex items-center justify-center text-brand-400 border border-white/10 shadow-inner"><Server className="w-10 h-10" /></div>
                    <div><span className="bg-red-500/20 text-red-300 px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest border border-red-500/30">SAAS MASTER</span><h1 className="text-4xl font-black text-white tracking-tight mt-2">Pilotage SaaS</h1><p className="text-slate-400 font-medium text-sm mt-1">Supervision technique et financière.</p></div>
                </div>
                <button className={`relative z-10 px-8 py-4 rounded-2xl font-black text-xs tracking-widest uppercase flex items-center gap-3 shadow-xl transition-all ${saasConfig.is_maintenance_mode ? 'bg-orange-500 text-white animate-pulse' : 'bg-brand-600 text-white'}`}><Activity className="w-4 h-4" /> STATUS: {saasConfig.is_maintenance_mode ? 'MAINTENANCE' : 'ONLINE'}</button>
            </div>
            {/* ... (Admin Global Stats Grid omitted for brevity, logic remains same) ... */}
             <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                 <div className="lg:col-span-2 bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm">
                     <div className="space-y-8">
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                             <div className="space-y-3"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Prix Abonnement Mensuel</label><div className="relative group"><Banknote className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-brand-600 transition-colors" /><input type="number" value={saasConfig.monthly_subscription_price} onChange={e => setSaasConfig({...saasConfig, monthly_subscription_price: Number(e.target.value)})} className="w-full pl-16 pr-6 py-5 rounded-[2rem] border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-brand-50 outline-none font-black text-slate-900 text-xl transition-all" /><span className="absolute right-6 top-1/2 -translate-y-1/2 text-[10px] font-black text-slate-400 uppercase">GNF / Mois</span></div></div>
                             <div className="space-y-3"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Période d'Essai</label><div className="relative group"><Clock className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-brand-600 transition-colors" /><input type="number" value={saasConfig.trial_period_days} onChange={e => setSaasConfig({...saasConfig, trial_period_days: Number(e.target.value)})} className="w-full pl-16 pr-6 py-5 rounded-[2rem] border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-brand-50 outline-none font-black text-slate-900 text-xl transition-all" /><span className="absolute right-6 top-1/2 -translate-y-1/2 text-[10px] font-black text-slate-400 uppercase">Jours</span></div></div>
                         </div>
                         <div className="space-y-3"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Support WhatsApp</label><div className="relative group"><Phone className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-emerald-600 transition-colors" /><input type="text" value={saasConfig.support_phone_number} onChange={e => setSaasConfig({...saasConfig, support_phone_number: e.target.value})} className="w-full pl-16 pr-6 py-5 rounded-[2rem] border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-emerald-50 outline-none font-black text-slate-900 text-lg transition-all" /></div></div>
                         <div className="bg-orange-50 p-6 rounded-[2rem] border border-orange-100 flex items-center justify-between"><div className="flex items-center gap-4"><div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-orange-500 shadow-sm"><AlertTriangle className="w-6 h-6" /></div><div><p className="font-black text-slate-900 text-sm uppercase">Mode Maintenance</p><p className="text-xs font-medium text-orange-700/70">Bloque l'accès à tous les gestionnaires.</p></div></div><button onClick={() => setSaasConfig({...saasConfig, is_maintenance_mode: !saasConfig.is_maintenance_mode})} className={`relative w-16 h-8 rounded-full transition-colors duration-300 ${saasConfig.is_maintenance_mode ? 'bg-orange-500' : 'bg-slate-300'}`}><div className={`absolute top-1 left-1 w-6 h-6 bg-white rounded-full shadow-md transition-transform duration-300 ${saasConfig.is_maintenance_mode ? 'translate-x-8' : 'translate-x-0'}`}></div></button></div>
                         <button onClick={handleSaveSaasConfig} disabled={saving} className="w-full py-6 bg-slate-900 hover:bg-black text-white rounded-[2rem] font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-3 shadow-xl transition-all active:scale-[0.98]">{saving ? <Loader2 className="w-5 h-5 animate-spin" /> : <Save className="w-4 h-4" />} ENREGISTRER CONFIGURATION</button>
                     </div>
                 </div>
                 <div className="space-y-6"><button onClick={handleLogout} className="w-full mt-8 py-5 bg-white border-2 border-slate-50 text-slate-400 hover:text-red-500 hover:border-red-50 rounded-[2.5rem] font-black text-xs tracking-widest uppercase flex items-center justify-center gap-3 transition-all group"><LogOut className="w-4 h-4 group-hover:translate-x-1 transition-transform" /> Se déconnecter</button></div>
            </div>
        </div>
      ) : (
        <>
            <div className="bg-white p-4 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col md:flex-row md:items-center justify-between gap-4"><div className="flex p-1.5 bg-slate-50 rounded-[2.5rem] w-full md:w-auto"><button onClick={() => setActiveTab('PROFILE')} className={`px-8 py-4 rounded-[2rem] font-black text-xs uppercase tracking-widest transition-all flex items-center gap-3 ${activeTab === 'PROFILE' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}><UserCircle className="w-4 h-4" /> Mon Compte</button>{(userProfile?.role === UserRole.GESTIONNAIRE_WIFI_ZONE || userProfile?.role === UserRole.ADMIN) && (<button onClick={() => setActiveTab('AGENCY')} className={`px-8 py-4 rounded-[2rem] font-black text-xs uppercase tracking-widest transition-all flex items-center gap-3 ${activeTab === 'AGENCY' ? 'bg-white text-brand-600 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}><Building2 className="w-4 h-4" /> Agence</button>)}</div><div className="flex items-center gap-3 px-4"><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Session :</span><span className="text-xs font-black text-slate-900">{userProfile?.role}</span></div></div>
            {activeTab === 'PROFILE' && (<div className="grid grid-cols-1 lg:grid-cols-3 gap-8"><div className="lg:col-span-2 bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm"><div className="flex items-center gap-4 mb-8"><div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black text-2xl shadow-xl">{userProfile?.full_name?.charAt(0) || 'U'}</div><div><h2 className="text-2xl font-black text-slate-900 tracking-tight">{userProfile?.full_name}</h2><p className="text-slate-400 font-medium text-sm">{userProfile?.email}</p></div></div><form onSubmit={handleUpdateProfile} className="space-y-6 max-w-lg"><Input label="Nom Complet" icon={<UserCircle className="w-5 h-5" />} value={profileForm.fullName} onChange={(v: string) => setProfileForm({...profileForm, fullName: v})} /><div className="pt-6 border-t border-slate-50"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2"><Lock className="w-3 h-3" /> Sécurité</p><div className="grid grid-cols-1 md:grid-cols-2 gap-4"><Input label="Nouveau Mot de passe" type="password" icon={<KeyRound className="w-5 h-5" />} value={profileForm.newPassword} onChange={(v: string) => setProfileForm({...profileForm, newPassword: v})} /><Input label="Confirmer" type="password" icon={<KeyRound className="w-5 h-5" />} value={profileForm.confirmPassword} onChange={(v: string) => setProfileForm({...profileForm, confirmPassword: v})} /></div></div><button type="submit" disabled={saving} className="w-full py-5 bg-slate-900 hover:bg-black text-white rounded-2xl font-black text-xs tracking-widest uppercase flex items-center justify-center gap-3 shadow-xl transition-all">{saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />} METTRE À JOUR</button></form></div><div className="space-y-6"><button onClick={handleLogout} className="w-full py-5 bg-white border-2 border-slate-50 text-slate-400 hover:text-red-500 hover:border-red-50 rounded-[2.5rem] font-black text-xs tracking-widest uppercase flex items-center justify-center gap-3 transition-all group"><LogOut className="w-4 h-4 group-hover:translate-x-1 transition-transform" /> Se déconnecter</button></div></div>)}
            {activeTab === 'AGENCY' && (userProfile?.role === UserRole.GESTIONNAIRE_WIFI_ZONE || userProfile?.role === UserRole.ADMIN) && (
                <div className="grid grid-cols-1 xl:grid-cols-3 gap-8 animate-in slide-in-from-right-4">
                    <div className="xl:col-span-2 space-y-8">
                        <div className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm">
                            <div className="flex items-center gap-3 mb-8"><Store className="w-5 h-5 text-brand-600" /><h2 className="text-lg font-black text-slate-900 uppercase tracking-tight">CONFIGURATION COMMERCIALE</h2></div>
                            <div className="space-y-6">
                                <Input label="EN-TÊTE REÇU WHATSAPP" icon={<Smartphone className="w-5 h-5" />} value={agencyForm.whatsappHeader} onChange={(v: string) => setAgencyForm({...agencyForm, whatsappHeader: v})} />
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                    <Input label="CONTACT SUPPORT CLIENT" icon={<Phone className="w-5 h-5" />} value={agencyForm.contactSupport} onChange={(v: string) => setAgencyForm({...agencyForm, contactSupport: v})} />

                                    {/* SELECTEUR DE DEVISE AJOUTÉ ICI */}
                                    <div className="space-y-3 text-left">
                                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Devise Principale</label>
                                        <div className="relative group">
                                            <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-brand-600 transition-colors">
                                                <Banknote className="w-5 h-5" />
                                            </div>
                                            <select
                                                value={agencyForm.currency}
                                                onChange={(e) => setAgencyForm({ ...agencyForm, currency: e.target.value })}
                                                className="w-full pl-14 pr-6 py-5 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-brand-50 outline-none font-bold text-slate-700 transition-all appearance-none cursor-pointer"
                                            >
                                                <option value="GNF">GNF (Franc Guinéen)</option>
                                                <option value="XAF">XAF (Franc CFA BEAC)</option>
                                                <option value="XOF">XOF (Franc CFA BCEAO)</option>
                                            </select>
                                        </div>
                                    </div>
                                </div>
                                <button onClick={handleSaveAgency} disabled={saving} className="w-full py-5 bg-brand-600 hover:bg-brand-700 text-white rounded-2xl font-black text-xs tracking-widest uppercase flex items-center justify-center gap-3 shadow-xl transition-all">{saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />} ENREGISTRER CONFIG</button>
                            </div>
                        </div>
                    </div>
                    <div className="space-y-8">
                        <div className="bg-[#1e293b] p-10 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden group">
                            <div className="absolute top-0 right-0 w-40 h-40 bg-brand-500 rounded-full blur-[80px] opacity-20 -mr-10 -mt-10 group-hover:opacity-30 transition-opacity"></div>
                            <div className="flex items-center gap-3 mb-10 text-brand-300 relative z-10"><Sparkles className="w-5 h-5" /><h2 className="text-sm font-black uppercase tracking-widest">STOCK LIVE</h2></div>
                            <div className="bg-white/5 border border-white/10 rounded-3xl p-6 mb-8 relative z-10"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">TOTAL VOUCHERS</p><p className="text-5xl font-black text-white tracking-tighter">{stockCount}</p></div>
                            <button onClick={handleCleanExpired} className="w-full py-4 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-2xl font-black text-[10px] tracking-widest uppercase flex items-center justify-center gap-2 transition-all"><Trash2 className="w-4 h-4" /> NETTOYER {expiredCount} EXPIRÉS</button>
                        </div>
                    </div>
                </div>
            )}
        </>
      )}
    </div>
  );
};
const Input = ({ label, icon, value, onChange, type = "text" }: any) => (<div className="space-y-3 text-left"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{label}</label><div className="relative group"><div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-brand-600 transition-colors">{icon}</div><input type={type} value={value} onChange={e => onChange(e.target.value)} className="w-full pl-14 pr-6 py-5 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-brand-50 outline-none font-bold text-slate-700 transition-all" /></div></div>);
export default Settings;

import React, { useEffect, useState, useCallback } from 'react';
import { Users as UsersIcon, Ticket, Wallet, ShoppingCart, Loader2, RefreshCcw, TrendingUp, ArrowUpRight, ShieldCheck, Building2, Clock, Activity, Globe, MapPin } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { db } from '../services/db';
import { UserRole, TicketStatus } from '../types';

const Dashboard: React.FC = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ revenue: 0, sold: 0, stock: 0, users: 0, pendingAgencies: 0, totalAgencies: 0, balance: 0 });
  const [recentSales, setRecentSales] = useState<any[]>([]);
  const [currentUserRole, setCurrentUserRole] = useState<UserRole | null>(null);
  const [agencyName, setAgencyName] = useState<string>('');
  const [currency, setCurrency] = useState('GNF');

  const fetchDashboardData = useCallback(async () => {
    try {
      setLoading(true);
      const { data: { user } } = await db.auth.getUser();
      if (!user) return;

      const { data: profile } = await db.from('users').select('role, tenant_id, balance, tenants(name, currency)').eq('id', user.id).maybeSingle();
      if (!profile) return;

      setCurrentUserRole(profile.role as UserRole);
      setAgencyName((profile.tenants as any)?.name || 'Mon Agence');
      setCurrency((profile.tenants as any)?.currency || 'GNF');

      const isAdminGlobal = profile.role === UserRole.ADMIN_GLOBAL;
      const isReseller = profile.role === UserRole.REVENDEUR;
      const tId = profile.tenant_id;

      let stockQuery = db.from('tickets').select('*', { count: 'exact', head: true });
      let soldQuery = db.from('tickets').select('*', { count: 'exact', head: true });
      let revQuery = db.from('sales_history').select('amount_paid');
      let userQuery = db.from('users').select('*', { count: 'exact', head: true });

      let salesQuery = db.from('sales_history')
        .select('*, tenants(name), tickets(username, ticket_profiles(name))')
        .order('sold_at', { ascending: false })
        .limit(6);

      if (isAdminGlobal) {
        // No filter for global admin
      } else if (isReseller) {
        stockQuery = stockQuery.eq('assigned_to', user.id).eq('status', TicketStatus.ASSIGNE);
        soldQuery = soldQuery.eq('sold_by', user.id).eq('status', TicketStatus.VENDU);
        revQuery = revQuery.eq('seller_id', user.id);
        salesQuery = salesQuery.eq('seller_id', user.id);
      } else {
        stockQuery = stockQuery.eq('tenant_id', tId).eq('status', TicketStatus.NEUF);
        soldQuery = soldQuery.eq('tenant_id', tId).eq('status', TicketStatus.VENDU);
        revQuery = revQuery.eq('tenant_id', tId);
        userQuery = userQuery.eq('tenant_id', tId);
        salesQuery = salesQuery.eq('tenant_id', tId);
      }

      const promises = [stockQuery, soldQuery, revQuery, userQuery, salesQuery];

      if (isAdminGlobal) {
        promises.push(db.from('tenants').select('*', { count: 'exact', head: true }).eq('subscription_status', 'EN_ATTENTE'));
        promises.push(db.from('tenants').select('*', { count: 'exact', head: true }));
      }

      const results = await Promise.all(promises);
      const stockRes = results[0];
      const soldRes = results[1];
      const revRes = results[2];
      const userRes = results[3];
      const salesRes = results[4];

      const pendingRes = isAdminGlobal ? results[5] : { count: 0 };
      const totalAgenciesRes = isAdminGlobal ? results[6] : { count: 0 };

      setStats({
        revenue: (revRes.data || []).reduce((acc: number, curr: any) => acc + Number(curr.amount_paid), 0) || 0,
        sold: soldRes.count || 0,
        stock: stockRes.count || 0,
        users: userRes.count || 0,
        pendingAgencies: pendingRes.count || 0,
        totalAgencies: totalAgenciesRes.count || 0,
        balance: profile.balance || 0 
      });
      setRecentSales(salesRes.data || []);
    } catch (err) { console.error(err); } finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchDashboardData(); }, [fetchDashboardData]);

  if (loading) return <div className="h-[60vh] flex flex-col items-center justify-center"><Loader2 className="w-8 h-8 text-brand-600 animate-spin mb-4" /></div>;

  const isAdminGlobal = currentUserRole === UserRole.ADMIN_GLOBAL;
  const isReseller = currentUserRole === UserRole.REVENDEUR;

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500">
      <header className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 lg:gap-6 bg-white p-6 md:p-8 rounded-[2rem] border border-slate-100 shadow-sm relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-slate-50 rounded-full blur-[80px] -mr-16 -mt-16 pointer-events-none"></div>

        <div className="relative z-10">
          <div className="flex flex-wrap items-center gap-2 mb-2">
            <span className="bg-slate-900 text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest flex items-center gap-1.5 w-fit">
              <Building2 className="w-3 h-3" /> {isAdminGlobal ? 'Super Admin' : agencyName}
            </span>
            {isReseller && <span className="bg-emerald-50 text-emerald-700 border border-emerald-100 px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-widest flex items-center gap-1.5"><Wallet className="w-3 h-3" /> Espace Revendeur</span>}
          </div>
          <h1 className="text-3xl md:text-4xl font-black text-slate-900 tracking-tight">
            {isAdminGlobal ? 'Vue d\'ensemble SaaS' : 'Tableau de Bord'}
          </h1>
          <p className="text-slate-500 font-medium text-sm mt-1 max-w-xl">
            {isAdminGlobal ? 'Métriques globales et performance du réseau.' : (isReseller ? 'Gérez vos ventes et votre stock personnel.' : 'Bienvenue sur votre espace de gestion WiFi.')}
          </p>
        </div>

        <div className="flex items-center gap-3 w-full lg:w-auto relative z-10">
          {!isAdminGlobal && (
            <button onClick={() => navigate('/sales')} className="flex-1 lg:flex-none bg-brand-600 hover:bg-brand-700 text-white px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl shadow-brand-200 transition-all active:scale-95"><ShoppingCart className="w-4 h-4" /> Guichet Vente</button>
          )}
          <button onClick={fetchDashboardData} className="p-4 bg-white border border-slate-200 rounded-2xl text-slate-400 hover:text-brand-600 hover:border-brand-200 transition-all shadow-sm"><RefreshCcw className="w-5 h-5" /></button>
        </div>
      </header>

      {/* KPI GRID */}
      <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4 md:gap-6">
        <StatCard 
            label={isAdminGlobal ? "Volume d'Affaires Global" : (isReseller ? "Vos Ventes (Total)" : "Chiffre d'Affaires")} 
            value={`${stats.revenue.toLocaleString()}`} 
            unit={currency} 
            icon={isAdminGlobal ? <Globe /> : <Wallet />} 
            color="text-brand-600" 
            bg="bg-brand-50" 
        />

        <StatCard 
            label={isAdminGlobal ? "Total Tickets Vendus" : "Tickets Vendus"} 
            value={stats.sold} 
            unit="Ventes" 
            icon={<TrendingUp />} 
            color="text-emerald-600" 
            bg="bg-emerald-50" 
        />

        {isAdminGlobal ? (
          <StatCard 
            label="Parc d'Agences" 
            value={stats.totalAgencies} 
            unit="Agences Inscrites" 
            icon={<Building2 />} 
            color="text-indigo-600" 
            bg="bg-indigo-50"
            onClick={() => navigate('/agencies')}
          />
        ) : (
          <StatCard 
            label={isReseller ? "Mon Stock (Assigné)" : "Stock Agence"} 
            value={stats.stock} 
            unit="Vouchers" 
            icon={<Ticket />} 
            color="text-indigo-600" 
            bg="bg-indigo-50" 
          />
        )}

        {isReseller ? (
             <StatCard label="Mon Solde (Prépayé)" value={stats.balance.toLocaleString()} unit={currency} icon={<Wallet />} color={stats.balance < 50000 ? "text-red-600" : "text-emerald-600"} bg={stats.balance < 50000 ? "bg-red-50" : "bg-emerald-50"} border={stats.balance < 50000} />
        ) : isAdminGlobal ? (
             <StatCard 
                label="Validations Requises" 
                value={stats.pendingAgencies} 
                unit="En attente" 
                icon={<Clock />} 
                color={stats.pendingAgencies > 0 ? "text-orange-600" : "text-slate-400"} 
                bg={stats.pendingAgencies > 0 ? "bg-orange-50" : "bg-slate-50"} 
                border={stats.pendingAgencies > 0}
                onClick={() => navigate('/agencies')}
             />
        ) : (
             <StatCard label="Membres Équipe" value={stats.users} unit="Utilisateurs" icon={<UsersIcon />} color="text-slate-600" bg="bg-slate-100" />
        )}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6 items-start">
        {/* Recent Transactions Table */}
        <div className="xl:col-span-2 bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="px-8 py-6 border-b border-slate-50 flex items-center justify-between">
            <h3 className="font-black text-slate-900 text-lg tracking-tight">
                {isAdminGlobal ? 'Flux Global' : (isReseller ? 'Mes dernières ventes' : 'Transactions récentes')}
            </h3>
            <button onClick={() => navigate('/history')} className="text-xs font-black text-brand-600 hover:text-brand-700 hover:underline uppercase tracking-widest">Voir l'historique</button>
          </div>
          <div className="divide-y divide-slate-50">
            {recentSales.length > 0 ? recentSales.map((sale, i) => (
