                          <select value={agencyFilter} onChange={(e) => setAgencyFilter(e.target.value)} className="w-full pl-12 pr-6 py-4 rounded-2xl border border-slate-100 bg-slate-50 font-bold text-slate-600 appearance-none outline-none focus:ring-4 focus:ring-indigo-50 transition-all text-sm"><option value="ALL">Toutes les agences</option>{agencies.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}</select>
                      </div>
                  )}
              </div>

              <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                  {(['TOUS', 'NEUF', 'VENDU'] as const).map((f) => (
                      <button key={f} onClick={() => setFilter(f)} className={`px-5 py-2.5 rounded-xl font-black text-[10px] tracking-widest uppercase transition-all whitespace-nowrap ${filter === f ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-white border border-slate-100 text-slate-400 hover:text-slate-600'}`}>
                          {f === 'NEUF' ? 'STOCK DISPO' : f}
                      </button>
                  ))}
              </div>
          </div>

          <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[800px]">
                  <thead>
                      <tr className="border-y border-slate-50 bg-slate-50/30 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                          {!isReseller && <th className="px-6 md:px-8 py-4">CODE</th>}
                          {(currentUser?.role === UserRole.ADMIN_GLOBAL || agencyFilter === 'ALL') && <th className="px-6 md:px-8 py-4">AGENCE</th>}
                          <th className="px-6 md:px-8 py-4">PROFIL</th>
                          <th className="px-6 md:px-8 py-4 text-right">PRIX</th>
                          <th className="px-6 md:px-8 py-4 text-center">STATUT</th>
                          {currentUser?.role !== UserRole.REVENDEUR && currentUser?.role !== UserRole.ADMIN_GLOBAL && <th className="px-6 md:px-8 py-4 text-right">ACTIONS</th>}
                      </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                      {loading ? (<tr><td colSpan={6} className="px-8 py-20 text-center"><Loader2 className="w-8 h-8 animate-spin mx-auto text-indigo-200" /></td></tr>) : tickets.length === 0 ? (<tr><td colSpan={6} className="px-8 py-20 text-center text-slate-300 font-bold uppercase text-xs">Aucun ticket</td></tr>) : tickets.map((item) => {
                          let statusLabel = 'VENDU';
                          let statusColor = 'bg-emerald-50 text-emerald-500';
                          if (item.status === TicketStatus.NEUF) { statusLabel = 'EN STOCK'; statusColor = 'bg-indigo-50 text-indigo-500'; }
