                      <h2 className="text-xl font-black tracking-widest uppercase">Fiche Transaction</h2>
                      <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-2">Référence ID: {selectedSale.id.split('-')[0]}</p>
