      {/* --- STOCK ASSIGNMENT HISTORY MODAL --- */}
      {showStockHistoryModal && selectedReseller && (
          <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 animate-in fade-in">
              <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-md" onClick={() => setShowStockHistoryModal(false)} />
              <div className="bg-white w-full max-w-2xl max-h-[80vh] rounded-[3rem] p-10 relative z-10 animate-in zoom-in-95 shadow-2xl flex flex-col">
                  <div className="flex items-center justify-between mb-8 shrink-0">
                      <div>
                          <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Suivi du Stock</h2>
                          <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-1">Pour {selectedReseller.full_name}</p>
                      </div>
                      <button onClick={() => setShowStockHistoryModal(false)} className="p-2 text-slate-300 hover:text-slate-900 hover:bg-slate-100 rounded-xl transition-all"><X className="w-6 h-6" /></button>
                  </div>

                  {/* Stats Rapides */}
                  <div className="flex gap-4 mb-6 shrink-0 overflow-x-auto pb-2">
                     <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-2xl min-w-[140px]">
                        <p className="text-[9px] font-black text-indigo-400 uppercase tracking-widest mb-1">Stock Actuel</p>
                        <p className="text-2xl font-black text-indigo-900">{stockHistory.filter(t => t.status === TicketStatus.ASSIGNE).length}</p>
                     </div>
                     <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-2xl min-w-[140px]">
                        <p className="text-[9px] font-black text-emerald-500 uppercase tracking-widest mb-1">Total Vendus</p>
                        <p className="text-2xl font-black text-emerald-900">{stockHistory.filter(t => t.status === TicketStatus.VENDU).length}</p>
                     </div>
                  </div>

                  <div className="overflow-y-auto custom-scrollbar grow -mx-4 px-4">
                      {loadingHistory ? (
                          <div className="py-20 flex justify-center"><Loader2 className="w-8 h-8 animate-spin text-slate-200" /></div>
                      ) : stockHistory.length === 0 ? (
                          <div className="py-20 text-center flex flex-col items-center gap-4 text-slate-300">
                              <Ticket className="w-12 h-12 opacity-20" />
                              <p className="font-bold uppercase text-[10px] tracking-widest">Aucun ticket assigné</p>
                          </div>
                      ) : (
                          <div className="space-y-3">
                              {stockHistory.map((ticket) => {
                                  const isSold = ticket.status === TicketStatus.VENDU;
                                  return (
                                    <div key={ticket.id} className="bg-slate-50 p-5 rounded-[2rem] border border-slate-100 flex items-center justify-between hover:bg-slate-100 transition-colors">
                                        <div className="flex items-center gap-4">
                                            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center shadow-sm border border-slate-100 ${isSold ? 'bg-emerald-100 text-emerald-600' : 'bg-indigo-100 text-indigo-600'}`}>
                                                {isSold ? <CheckCircle2 className="w-4 h-4" /> : <Ticket className="w-4 h-4" />}
                                            </div>
                                            <div>
                                                <p className="font-black text-slate-900">{ticket.username}</p>
                                                <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                                                    <Tag className="w-3 h-3" />
                                                    <span>{ticket.ticket_profiles?.name}</span>
                                                    <span>•</span>
                                                    <span>{Number(ticket.ticket_profiles?.price).toLocaleString()} {currency}</span>
                                                </div>
                                            </div>
                                        </div>
                                        <div className="text-right">
                                            <div className={`inline-block px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest mb-1 ${isSold ? 'bg-emerald-50 text-emerald-600' : 'bg-indigo-50 text-indigo-600'}`}>
                                                {isSold ? 'VENDU' : 'EN STOCK'}
                                            </div>
                                            <p className="text-[10px] text-slate-400 font-medium">
                                                {isSold 
                                                    ? (ticket.sold_at ? new Date(ticket.sold_at).toLocaleDateString() : '-') 
                                                    : 'Non vendu'}
                                            </p>
                                        </div>
                                    </div>
                                  );
                              })}
                          </div>
                      )}
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};
export default Resellers;

import React, { useEffect, useState } from 'react';
import { Tag, Search, Loader2, Pencil, X, Save, AlertCircle, CheckCircle2, DollarSign, Zap, Ticket } from 'lucide-react';
import { db } from '../services/db';

const Profiles: React.FC = () => {
  const [profiles, setProfiles] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingProfile, setEditingProfile] = useState<any | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [toast, setToast] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const [editPrice, setEditPrice] = useState('');
  const [currency, setCurrency] = useState('GNF');

  useEffect(() => { fetchProfiles(); }, []);
  const showToast = (type: 'success' | 'error', message: string) => { setToast({ type, message }); setTimeout(() => setToast(null), 3000); };

  const fetchProfiles = async () => {
    try {
      setLoading(true);
      const { data: { user } } = await db.auth.getUser();
      if (!user) return;
      const { data: profile } = await db.from('users').select('tenant_id, tenants(currency)').eq('id', user.id).single();
      const { data, error } = await db.from('ticket_profiles').select('*, tickets(count)').eq('tenant_id', profile?.tenant_id).order('name');
      if (error) throw error;
      setProfiles(data || []);
      setCurrency((profile?.tenants as any)?.currency || 'GNF');
    } catch (err: any) { showToast('error', err.message); } finally { setLoading(false); }
  };

  const handleUpdatePrice = async (e: React.FormEvent) => {
    e.preventDefault(); if (!editingProfile || !editPrice) return;
    setIsSubmitting(true);
    try {
      const { error } = await db.from('ticket_profiles').update({ price: Number(editPrice) }).eq('id', editingProfile.id);
      if (error) throw error;
      showToast('success', `Prix mis à jour pour ${editingProfile.name}`);
      setEditingProfile(null); fetchProfiles();
    } catch (err: any) { showToast('error', err.message); } finally { setIsSubmitting(false); }
  };
  const filteredProfiles = profiles.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="space-y-8 pb-20 animate-in fade-in duration-500">
      {toast && (<div className={`fixed top-6 right-6 z-[60] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right-10 border ${toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-red-600 text-white border-red-500'}`}>{toast.type === 'success' ? <CheckCircle2 className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}<p className="font-bold text-sm">{toast.message}</p></div>)}
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6"><div><div className="flex items-center gap-2 text-brand-600 mb-1"><Zap className="w-4 h-4 fill-current" /><span className="text-[10px] font-black uppercase tracking-widest">Gestion de l'offre</span></div><h1 className="text-3xl font-extrabold text-slate-900 tracking-tight leading-none">Forfaits WiFi</h1><p className="text-slate-400 font-medium text-sm mt-2">Définissez vos prix et surveillez la disponibilité.</p></div></header>
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden"><div className="p-8 border-b border-slate-50 flex flex-col md:flex-row md:items-center justify-between gap-4"><div className="relative max-w-md w-full group"><Search className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-brand-600 transition-colors" /><input type="text" placeholder="Chercher un forfait..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-14 pr-6 py-4 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-brand-50 outline-none font-bold text-slate-700 transition-all" /></div><div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50 px-4 py-2 rounded-xl"><Ticket className="w-4 h-4" /> {profiles.length} Types de forfaits</div></div><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 p-8">{loading ? (<div className="col-span-full py-20 text-center"><Loader2 className="w-10 h-10 animate-spin mx-auto text-brand-600/20" /></div>) : filteredProfiles.length > 0 ? filteredProfiles.map((p) => (<div key={p.id} className="bg-slate-50/50 p-8 rounded-[2.5rem] border border-slate-100 hover:border-brand-500 hover:bg-white transition-all group relative overflow-hidden"><div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10"><Tag className="w-20 h-20 text-slate-900" /></div><div className="flex justify-between items-start mb-6"><div className="w-12 h-12 bg-brand-50 text-brand-600 rounded-2xl flex items-center justify-center"><DollarSign className="w-6 h-6" /></div><button onClick={() => { setEditingProfile(p); setEditPrice(p.price.toString()); }} className="p-2.5 bg-white text-slate-300 hover:text-slate-900 rounded-xl shadow-sm border border-slate-100 transition-all"><Pencil className="w-4 h-4" /></button></div><h3 className="text-xl font-black text-slate-900 mb-1">{p.name}</h3><p className="text-2xl font-black text-brand-600 mb-6">{p.price.toLocaleString()} <span className="text-[10px] uppercase">{currency}</span></p><div className="pt-6 border-t border-slate-100 flex items-center justify-between"><div className="flex flex-col"><span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">En Stock</span><span className={`text-sm font-black ${p.tickets?.[0]?.count < 20 ? 'text-red-500' : 'text-slate-900'}`}>{p.tickets?.[0]?.count || 0} pcs</span></div><div className="h-1.5 w-24 bg-slate-100 rounded-full overflow-hidden"><div className={`h-full rounded-full ${p.tickets?.[0]?.count < 20 ? 'bg-red-500' : 'bg-brand-500'}`} style={{ width: `${Math.min(100, ((p.tickets?.[0]?.count || 0) / 100) * 100)}%` }} /></div></div></div>)) : (<div className="col-span-full py-20 text-center text-slate-300 font-bold uppercase text-xs">Aucun forfait configuré</div>)}</div></div>
      {editingProfile && (<div className="fixed inset-0 z-[60] flex items-center justify-center p-4"><div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => !isSubmitting && setEditingProfile(null)} /><form onSubmit={handleUpdatePrice} className="bg-white w-full max-w-sm rounded-[3rem] p-10 relative z-10 animate-in zoom-in-95 shadow-2xl"><button type="button" onClick={() => setEditingProfile(null)} className="absolute top-8 right-8 text-slate-300 hover:text-slate-900"><X className="w-6 h-6" /></button><h2 className="text-2xl font-black mb-2 uppercase text-slate-900 tracking-tight">Modifier Prix</h2><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8">{editingProfile.name}</p><div className="space-y-6"><div className="relative"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nouveau Tarif ({currency})</label><input type="number" required autoFocus value={editPrice} onChange={e => setEditPrice(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black text-2xl text-slate-900 outline-none focus:bg-white transition-all" /><span className="absolute right-6 top-[55px] text-slate-300 font-black">{currency}</span></div></div><button type="submit" disabled={isSubmitting} className="w-full mt-10 py-5 bg-slate-900 hover:bg-black text-white rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 shadow-xl">{isSubmitting ? <Loader2 className="w-5 h-5 animate-spin" /> : <><Save className="w-4 h-4" /> ENREGISTRER</>}</button></form></div>)}
    </div>
  );
};
export default Profiles;

