            {activeTab === 'PROFILE' && (<div className="grid grid-cols-1 lg:grid-cols-3 gap-8"><div className="lg:col-span-2 bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm"><div className="flex items-center gap-4 mb-8"><div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white font-black text-2xl shadow-xl">{userProfile?.full_name?.charAt(0) || 'U'}</div><div><h2 className="text-2xl font-black text-slate-900 tracking-tight">{userProfile?.full_name}</h2><p className="text-slate-400 font-medium text-sm">{userProfile?.email}</p></div></div><form onSubmit={handleUpdateProfile} className="space-y-6 max-w-lg"><Input label="Nom Complet" icon={<UserCircle className="w-5 h-5" />} value={profileForm.fullName} onChange={(v: string) => setProfileForm({...profileForm, fullName: v})} /><div className="pt-6 border-t border-slate-50"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center gap-2"><Lock className="w-3 h-3" /> Sécurité</p><div className="grid grid-cols-1 md:grid-cols-2 gap-4"><Input label="Nouveau Mot de passe" type="password" icon={<KeyRound className="w-5 h-5" />} value={profileForm.newPassword} onChange={(v: string) => setProfileForm({...profileForm, newPassword: v})} /><Input label="Confirmer" type="password" icon={<KeyRound className="w-5 h-5" />} value={profileForm.confirmPassword} onChange={(v: string) => setProfileForm({...profileForm, confirmPassword: v})} /></div></div><button type="submit" disabled={saving} className="w-full py-5 bg-slate-900 hover:bg-black text-white rounded-2xl font-black text-xs tracking-widest uppercase flex items-center justify-center gap-3 shadow-xl transition-all">{saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />} METTRE À JOUR</button></form></div><div className="space-y-6"><button onClick={handleLogout} className="w-full py-5 bg-white border-2 border-slate-50 text-slate-400 hover:text-red-500 hover:border-red-50 rounded-[2.5rem] font-black text-xs tracking-widest uppercase flex items-center justify-center gap-3 transition-all group"><LogOut className="w-4 h-4 group-hover:translate-x-1 transition-transform" /> Se déconnecter</button></div></div>)}
            {activeTab === 'AGENCY' && (userProfile?.role === UserRole.GESTIONNAIRE_WIFI_ZONE || userProfile?.role === UserRole.ADMIN) && (
                <div className="grid grid-cols-1 xl:grid-cols-3 gap-8 animate-in slide-in-from-right-4">
                    <div className="xl:col-span-2 space-y-8">
                        <div className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm">
                            <div className="flex items-center gap-3 mb-8"><Store className="w-5 h-5 text-brand-600" /><h2 className="text-lg font-black text-slate-900 uppercase tracking-tight">CONFIGURATION COMMERCIALE</h2></div>
                            <div className="space-y-6">
                                <Input label="EN-TÊTE REÇU WHATSAPP" icon={<Smartphone className="w-5 h-5" />} value={agencyForm.whatsappHeader} onChange={(v: string) => setAgencyForm({...agencyForm, whatsappHeader: v})} />
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                    <Input label="CONTACT SUPPORT CLIENT" icon={<Phone className="w-5 h-5" />} value={agencyForm.contactSupport} onChange={(v: string) => setAgencyForm({...agencyForm, contactSupport: v})} />

                                    {/* SELECTEUR DE DEVISE AJOUTÉ ICI */}
                                    <div className="space-y-3 text-left">
                                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Devise Principale</label>
                                        <div className="relative group">
                                            <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-brand-600 transition-colors">
                                                <Banknote className="w-5 h-5" />
                                            </div>
                                            <select
                                                value={agencyForm.currency}
                                                onChange={(e) => setAgencyForm({ ...agencyForm, currency: e.target.value })}
                                                className="w-full pl-14 pr-6 py-5 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-brand-50 outline-none font-bold text-slate-700 transition-all appearance-none cursor-pointer"
                                            >
                                                <option value="GNF">GNF (Franc Guinéen)</option>
                                                <option value="XAF">XAF (Franc CFA BEAC)</option>
                                                <option value="XOF">XOF (Franc CFA BCEAO)</option>
                                            </select>
                                        </div>
                                    </div>
                                </div>
                                <button onClick={handleSaveAgency} disabled={saving} className="w-full py-5 bg-brand-600 hover:bg-brand-700 text-white rounded-2xl font-black text-xs tracking-widest uppercase flex items-center justify-center gap-3 shadow-xl transition-all">{saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />} ENREGISTRER CONFIG</button>
                            </div>
                        </div>
                    </div>
                    <div className="space-y-8">
                        <div className="bg-[#1e293b] p-10 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden group">
                            <div className="absolute top-0 right-0 w-40 h-40 bg-brand-500 rounded-full blur-[80px] opacity-20 -mr-10 -mt-10 group-hover:opacity-30 transition-opacity"></div>
                            <div className="flex items-center gap-3 mb-10 text-brand-300 relative z-10"><Sparkles className="w-5 h-5" /><h2 className="text-sm font-black uppercase tracking-widest">STOCK LIVE</h2></div>
                            <div className="bg-white/5 border border-white/10 rounded-3xl p-6 mb-8 relative z-10"><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">TOTAL VOUCHERS</p><p className="text-5xl font-black text-white tracking-tighter">{stockCount}</p></div>
                            <button onClick={handleCleanExpired} className="w-full py-4 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-2xl font-black text-[10px] tracking-widest uppercase flex items-center justify-center gap-2 transition-all"><Trash2 className="w-4 h-4" /> NETTOYER {expiredCount} EXPIRÉS</button>
                        </div>
                    </div>
                </div>
            )}
        </>
      )}
    </div>
  );
};
const Input = ({ label, icon, value, onChange, type = "text" }: any) => (<div className="space-y-3 text-left"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{label}</label><div className="relative group"><div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-brand-600 transition-colors">{icon}</div><input type={type} value={value} onChange={e => onChange(e.target.value)} className="w-full pl-14 pr-6 py-5 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-brand-50 outline-none font-bold text-slate-700 transition-all" /></div></div>);
export default Settings;

import React, { useState, useEffect, useCallback } from 'react';
import { db } from '../services/db';
import { History as HistoryIcon, Search, Loader2, Info, X, QrCode, Share2, RefreshCcw, RotateCcw, AlertTriangle, CheckCircle2, Building2, Calendar, AlertCircle, Printer, Filter, User, Tag, CalendarRange } from 'lucide-react';
import { UserRole, Sale } from '../types';

const History: React.FC = () => {
  const [sales, setSales] = useState<Sale[]>([]);
  const [loading, setLoading] = useState(true);

  // Filtres de base
  const [searchTerm, setSearchTerm] = useState('');
  const [agencyFilter, setAgencyFilter] = useState<string>('ALL');

  // Filtres Avancés
  const [dateStart, setDateStart] = useState('');
  const [dateEnd, setDateEnd] = useState('');
  const [sellerFilter, setSellerFilter] = useState('ALL');
  const [profileFilter, setProfileFilter] = useState('ALL');
  const [showFilters, setShowFilters] = useState(false);

  // Listes pour les dropdowns
  const [agencies, setAgencies] = useState<any[]>([]);
  const [sellersList, setSellersList] = useState<any[]>([]);
  const [profilesList, setProfilesList] = useState<any[]>([]);

  const [stats, setStats] = useState({ totalCount: 0, totalRevenue: 0 });
  const [toast, setToast] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const [currentUser, setCurrentUser] = useState<{ id: string, role: UserRole, tenant_id?: string, tenantName?: string } | null>(null);
  const [selectedSale, setSelectedSale] = useState<Sale | null>(null);
  const [saleToCancel, setSaleToCancel] = useState<Sale | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [currency, setCurrency] = useState('GNF');

  const notify = useCallback((type: 'success' | 'error', message: string) => { setToast({ type, message }); setTimeout(() => setToast(null), 4000); }, []);

  useEffect(() => { fetchInitialContext(); }, []);

  // Rechargement des données quand un filtre change
  useEffect(() => { 
      if (currentUser) fetchHistory(); 
  }, [agencyFilter, searchTerm, currentUser, dateStart, dateEnd, sellerFilter, profileFilter]);

  // Rechargement des listes déroulantes (Vendeurs/Forfaits) quand l'agence change (pour Global Admin)
  useEffect(() => {
      if (currentUser) fetchFilterOptions();
  }, [currentUser, agencyFilter]);

  const fetchInitialContext = async () => {
    try {
      const { data: { user } } = await db.auth.getUser();
      if (!user) return;
      const { data: userData } = await db.from('users').select('role, tenant_id, tenants(name, currency)').eq('id', user.id).single();
      const currentRole = userData?.role as UserRole;
      const tenantName = (userData?.tenants as any)?.name;
      const tenantCurrency = (userData?.tenants as any)?.currency || 'GNF';

      setCurrentUser({ id: user.id, role: currentRole, tenant_id: userData?.tenant_id, tenantName });
      setCurrency(tenantCurrency);

      if (currentRole === UserRole.ADMIN_GLOBAL) { 
          const { data: tData } = await db.from('tenants').select('id, name').order('name'); 
          setAgencies(tData || []); 
      }
    } catch (err) { console.error(err); }
  };

  const fetchFilterOptions = async () => {
      if (!currentUser) return;
      try {
          // Déterminer le scope (Tenant ID)
          let targetTenantId = currentUser.tenant_id;
          if (currentUser.role === UserRole.ADMIN_GLOBAL) {
              if (agencyFilter !== 'ALL') targetTenantId = agencyFilter;
              else targetTenantId = undefined; // Pas de filtre spécifique
          }

          // 1. Récupérer les vendeurs
          let userQuery = db.from('users').select('id, full_name').neq('role', 'CLIENT');
          if (targetTenantId) userQuery = userQuery.eq('tenant_id', targetTenantId);
          const { data: usersData } = await userQuery.order('full_name');
          setSellersList(usersData || []);

          // 2. Récupérer les profils
          let profileQuery = db.from('ticket_profiles').select('id, name');
          if (targetTenantId) profileQuery = profileQuery.eq('tenant_id', targetTenantId);
          const { data: profilesData } = await profileQuery.order('name');
          setProfilesList(profilesData || []);

      } catch (err) { console.error("Erreur chargement filtres", err); }
  };

  const fetchHistory = async () => {
    if (!currentUser) return;
    try {
      setLoading(true);

      // Construction de la requête principale
      // Note: tickets!inner est nécessaire pour filtrer sur les propriétés du ticket (comme profile_id)
      let query = db.from('sales_history')
        .select(`
            id, amount_paid, sold_at, metadata, ticket_id, tenant_id, seller_id, 
            tenants(name), 
            tickets!inner(id, username, password, status, profile_id, ticket_profiles(name)), 
            users(full_name)
        `);

      // Filtre Rôle
      if (currentUser.role === UserRole.REVENDEUR) {
          query = query.eq('seller_id', currentUser.id);
      } else if (currentUser.role === UserRole.ADMIN_GLOBAL) { 
          if (agencyFilter !== 'ALL') query = query.eq('tenant_id', agencyFilter); 
      } else { 
          query = query.eq('tenant_id', currentUser.tenant_id); 
      }

      // Filtre Recherche Texte
      if (searchTerm) query = query.ilike('tickets.username', `%${searchTerm}%`);

      // Filtres Avancés
      if (dateStart) query = query.gte('sold_at', `${dateStart}T00:00:00`);
      if (dateEnd) query = query.lte('sold_at', `${dateEnd}T23:59:59`);
      if (sellerFilter !== 'ALL') query = query.eq('seller_id', sellerFilter);
      if (profileFilter !== 'ALL') query = query.eq('tickets.profile_id', profileFilter);

      const { data, error } = await query.order('sold_at', { ascending: false }).limit(500);

      if (error) throw error;
      const results = (data as unknown as Sale[]) || [];
      setSales(results);

      // Calcul des totaux basés sur le résultat filtré
      setStats({ 
          totalCount: results.length, 
          totalRevenue: results.reduce((acc, curr) => acc + Number(curr.amount_paid), 0) 
      });

    } catch (err: any) { 
        console.error("History fetch error:", err); 
        notify('error', "Erreur chargement historique");
    } finally { 
        setLoading(false); 
    }
  };

  const resetFilters = () => {
      setSearchTerm('');
      setDateStart('');
      setDateEnd('');
      setSellerFilter('ALL');
      setProfileFilter('ALL');
      if (currentUser?.role === UserRole.ADMIN_GLOBAL) setAgencyFilter('ALL');
  };

  const handlePrint = () => { window.print(); };
  const initiateCancellation = (sale: Sale) => { if (!currentUser) return; const canCancel = currentUser.role === UserRole.ADMIN_GLOBAL || currentUser.role === UserRole.GESTIONNAIRE_WIFI_ZONE || (currentUser.role === UserRole.REVENDEUR && sale.seller_id === currentUser.id); if (!canCancel) { notify('error', "Accès refusé."); return; } setSaleToCancel(sale); };
  const confirmCancellation = async () => { if (!saleToCancel) return; setIsProcessing(true); const targetTicketId = saleToCancel.ticket_id || saleToCancel.tickets?.id; try { const { data: sellerProfile } = await db.from('users').select('role, balance').eq('id', saleToCancel.seller_id).single(); if (sellerProfile?.role === UserRole.REVENDEUR) await db.from('users').update({ balance: Number(sellerProfile.balance || 0) + Number(saleToCancel.amount_paid) }).eq('id', saleToCancel.seller_id); await db.from('tickets').update({ status: 'NEUF', sold_at: null, sold_by: null, assigned_to: null }).eq('id', targetTicketId); await db.from('sales_history').delete().eq('id', saleToCancel.id); notify('success', "Vente annulée."); setSaleToCancel(null); setSelectedSale(null); await fetchHistory(); } catch (err: any) { notify('error', "Échec : " + err.message); } finally { setIsProcessing(false); } };
  const handleWhatsAppShare = () => { if (!selectedSale) return; window.open(`https://wa.me/?text=${encodeURIComponent(`*TICKET WIFI*\n\n🎟️ CODE : *${selectedSale.tickets?.username}*\n📦 FORFAIT : ${selectedSale.tickets?.ticket_profiles?.name}\n💰 PRIX : ${Number(selectedSale.amount_paid).toLocaleString()} ${currency}\n\nMerci !`)}`, '_blank'); };

  return (
    <div className="space-y-6 font-sans pb-24 animate-in fade-in duration-500 relative">
