                     <div className="h-10 w-10 rounded-full bg-brand-500/20 text-brand-400 flex items-center justify-center"><Ticket className="w-5 h-5" /></div>
                   </div>
                 </>
               )}
            </div>
          </div>
          <button onClick={() => navigate('/history')} className="relative z-10 w-full mt-6 py-4 bg-brand-600 hover:bg-brand-500 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] transition-colors flex items-center justify-center gap-2 shadow-lg shadow-brand-900/50">
             Rapport Détaillé <ArrowUpRight className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* MODAL DE DECLARATION DE VERSEMENT */}
      {showDepositModal && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 animate-in fade-in">
              <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setShowDepositModal(false)} />
              <form onSubmit={handleSubmitDeposit} className="bg-white w-full max-w-sm rounded-[3rem] p-10 relative z-10 animate-in zoom-in-95 shadow-2xl">
                  <button type="button" onClick={() => setShowDepositModal(false)} className="absolute top-8 right-8 text-slate-300 hover:text-slate-900 transition-colors"><X className="w-6 h-6" /></button>
                  <h2 className="text-2xl font-black mb-8 uppercase text-center text-slate-900 tracking-tight">Déclarer un versement</h2>
                  <div className="space-y-6">
                      <div>
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Montant Versé ({currency})</label>
                          <input type="number" required placeholder="ex: 100000" value={depositAmount} onChange={e => setDepositAmount(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black text-xl outline-none focus:bg-white focus:ring-4 focus:ring-emerald-50 transition-all" />
                      </div>
                      <div>
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Méthode</label>
                          <div className="relative">
                              <select value={depositMethod} onChange={e => setDepositMethod(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black outline-none appearance-none focus:bg-white focus:ring-4 focus:ring-emerald-50 transition-all cursor-pointer">
                                  <option value="CASH">Espèces / Main à main</option>
                                  <option value="MOMO">Mobile Money (MTN)</option>
                                  <option value="OM">Orange Money</option>
                                  <option value="VIREMENT">Virement Bancaire</option>
                              </select>
                          </div>
                      </div>
                      <div className="animate-in slide-in-from-top-2 fade-in">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Référence / Numéro</label>
                          <div className="relative group">
                              <Smartphone className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-emerald-600 transition-colors" />
                              <input type="text" required placeholder="Preuve du paiement" value={depositReference} onChange={e => setDepositReference(e.target.value)} className="w-full pl-14 pr-6 py-5 bg-slate-50 border border-slate-100 rounded-2xl font-black text-lg outline-none focus:bg-white focus:ring-4 focus:ring-emerald-50 transition-all" />
                          </div>
                      </div>
                  </div>
                  <button type="submit" disabled={isSubmittingDeposit} className="w-full mt-10 py-5 bg-emerald-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 shadow-xl shadow-emerald-100 hover:bg-emerald-700 transition-all active:scale-95">
                      {isSubmittingDeposit ? <Loader2 className="w-5 h-5 animate-spin" /> : "ENVOYER LA DEMANDE"}
                  </button>
              </form>
          </div>
      )}
    </div>
  );
};

const StatCard = ({ label, value, unit, icon, color, bg, onClick, border }: any) => (
  <div 
    onClick={onClick} 
    className={`bg-white p-6 md:p-8 rounded-[2.5rem] border ${border ? 'border-orange-200 shadow-orange-100' : 'border-slate-100'} shadow-sm hover:shadow-xl transition-all duration-300 group ${onClick ? 'cursor-pointer hover:border-brand-200 active:scale-95' : ''}`}
  >
    <div className="flex items-start justify-between mb-6">
      <div className={`w-12 h-12 ${bg} ${color} rounded-2xl flex items-center justify-center shadow-inner group-hover:scale-110 transition-transform`}>
        {React.cloneElement(icon, { className: "w-6 h-6" })}
      </div>
      {onClick && <ArrowUpRight className="w-5 h-5 text-slate-200 group-hover:text-brand-400 transition-colors" />}
    </div>
    <div>
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 truncate">{label}</p>
      <div className="flex items-baseline gap-1.5 flex-wrap">
        <h3 className="text-3xl font-black text-slate-900 tracking-tight">{value}</h3>
        <span className="text-[10px] font-bold text-slate-400 uppercase">{unit}</span>
      </div>
    </div>
  </div>
);

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Users, Wallet, Plus, Search, Loader2, TrendingUp, TrendingDown, ArrowRight, History, Ticket, DollarSign, X, Building2, CheckCircle2, AlertCircle, Smartphone, Filter, LayoutGrid, List, Calendar, CreditCard, UserCircle, ClipboardList, Tag, BarChart3, PieChart, Check, Ban, Bell } from 'lucide-react';
import { db } from '../services/db';
import { UserRole, User, TicketStatus } from '../types';

const Resellers: React.FC = () => {
  const [resellers, setResellers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [viewMode, setViewMode] = useState<'CARDS' | 'TABLE'>('CARDS');

  // Modals States
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [showAssignModal, setShowAssignModal] = useState(false);
  const [showHistoryModal, setShowHistoryModal] = useState(false);
  const [showStockHistoryModal, setShowStockHistoryModal] = useState(false);
  const [showStatsModal, setShowStatsModal] = useState(false); 

  const [selectedReseller, setSelectedReseller] = useState<User | null>(null);

  // Payment Form Data
  const [amount, setAmount] = useState('');
  const [method, setMethod] = useState('CASH');
  const [paymentPhone, setPaymentPhone] = useState('');

  // Assign Form Data
  const [ticketProfiles, setTicketProfiles] = useState<any[]>([]);
  const [selectedProfileId, setSelectedProfileId] = useState('');
  const [quantity, setQuantity] = useState('50');

  // Data States
  const [processing, setProcessing] = useState(false);
  const [paymentHistory, setPaymentHistory] = useState<any[]>([]);
  const [stockHistory, setStockHistory] = useState<any[]>([]);
  const [statsData, setStatsData] = useState<any>(null); 
  const [loadingHistory, setLoadingHistory] = useState(false);
  const [toast, setToast] = useState<any>(null);

  // Admin Global States
  const [agencies, setAgencies] = useState<any[]>([]);
  const [agencyFilter, setAgencyFilter] = useState<string>('ALL');
  const [currency, setCurrency] = useState('GNF');

  // Pending Requests State
  const [pendingRequests, setPendingRequests] = useState<any[]>([]);

  useEffect(() => {
    const init = async () => {
      const { data: { user } } = await db.auth.getUser();
      if (user) {
        const { data: profile } = await db.from('users').select('*, tenants(currency)').eq('id', user.id).single();
        setCurrentUser(profile);
        setCurrency((profile.tenants as any)?.currency || 'GNF');

        if (profile.role === UserRole.ADMIN_GLOBAL) {
          const { data: tData } = await db.from('tenants').select('id, name').order('name');
          setAgencies(tData || []);
        }
      }
    };
    init();
  }, []);

  useEffect(() => {
    if (currentUser) {
        fetchResellers();
        if (currentUser.role !== UserRole.REVENDEUR) {
            fetchPendingRequests();
        }
    }
  }, [currentUser, agencyFilter]);

  const fetchPendingRequests = async () => {
      try {
          let query = db.from('payments')
            .select('*, users!payments_reseller_id_fkey(full_name)')
            .eq('status', 'PENDING')
            .order('created_at', { ascending: false });

          if (currentUser.role === UserRole.ADMIN_GLOBAL) {
              if (agencyFilter !== 'ALL') query = query.eq('tenant_id', agencyFilter);
          } else {
              query = query.eq('tenant_id', currentUser.tenant_id);
          }

          const { data } = await query;
          setPendingRequests(data || []);
      } catch (err) { console.error("Erreur chargement demandes", err); }
  };

  const handleApproveRequest = async (request: any) => {
      if(processing) return;
      setProcessing(true);
      try {
          // 1. Update status
          const { error: updateError } = await db.from('payments').update({ status: 'APPROVED' }).eq('id', request.id);
          if (updateError) throw updateError;

          // 2. Update balance
          const { data: user } = await db.from('users').select('balance').eq('id', request.reseller_id).single();
          const currentBalance = Number(user?.balance) || 0;
          await db.from('users').update({ balance: currentBalance + Number(request.amount) }).eq('id', request.reseller_id);

          setToast({ type: 'success', message: "Rechargement validé." });
          fetchPendingRequests();
          fetchResellers(); // Update list to show new balance
      } catch(err: any) {
          setToast({ type: 'error', message: err.message });
      } finally {
          setProcessing(false);
      }
  };

  const handleRejectRequest = async (request: any) => {
      if(!confirm("Rejeter cette demande ?") || processing) return;
      setProcessing(true);
      try {
          await db.from('payments').update({ status: 'REJECTED' }).eq('id', request.id);
          setToast({ type: 'success', message: "Demande rejetée." });
          fetchPendingRequests();
      } catch(err: any) {
          setToast({ type: 'error', message: err.message });
      } finally {
          setProcessing(false);
      }
  };

  const fetchResellers = async () => {
    try {
      setLoading(true);
      const isAdminGlobal = currentUser.role === UserRole.ADMIN_GLOBAL;

      // On récupère aussi sales_history pour calculer le CA total
      let query = db.from('users')
        .select('*, tenants(name), sales_history(amount_paid)') 
        .eq('role', UserRole.REVENDEUR)
        .eq('is_active', true);

      if (isAdminGlobal) {
        if (agencyFilter !== 'ALL') query = query.eq('tenant_id', agencyFilter);
      } else {
        query = query.eq('tenant_id', currentUser.tenant_id);
      }

      const { data: rData, error } = await query;
      if (error) throw error;

      // Calcul du revenu total pour chaque revendeur
      const processedData = (rData || []).map((r: any) => ({
        ...r,
        total_revenue: r.sales_history?.reduce((acc: number, curr: any) => acc + Number(curr.amount_paid), 0) || 0
      }));

      setResellers(processedData);

      if (!isAdminGlobal && currentUser.tenant_id) {
        loadProfiles(currentUser.tenant_id);
      }
    } catch (err) { console.error(err); } finally { setLoading(false); }
  };

  const loadProfiles = async (tenantId: string) => {
    const { data: pData } = await db.from('ticket_profiles')
      .select('id, name, price, tickets(count)')
      .eq('tenant_id', tenantId);
    const availableProfiles = (pData || []).filter((p: any) => (p.tickets?.[0]?.count || 0) > 0);
    setTicketProfiles(availableProfiles);
  };

  const fetchPaymentHistoryData = async (resellerId: string) => {
    setLoadingHistory(true);
    try {
      const { data, error } = await db.from('payments')
        .select('*, users!payments_created_by_fkey(full_name)') 
        .eq('reseller_id', resellerId)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setPaymentHistory(data || []);
    } catch (err: any) {
        console.error(err);
        setToast({ type: 'error', message: "Impossible de charger l'historique." });
    } finally {
        setLoadingHistory(false);
    }
  };

  const fetchStockHistoryData = async (resellerId: string) => {
    setLoadingHistory(true);
    try {
        const { data, error } = await db.from('tickets')
            .select('id, username, status, sold_at, imported_at, ticket_profiles(name, price)')
            .or(`assigned_to.eq.${resellerId},sold_by.eq.${resellerId}`)
            .order('sold_at', { ascending: false, nullsFirst: true });

        if (error) throw error;
        setStockHistory(data || []);
    } catch (err: any) {
        console.error(err);
        setToast({ type: 'error', message: "Impossible de charger l'historique des tickets." });
    } finally {
        setLoadingHistory(false);
    }
  };

  // --- STATS CALCULATION ---
  const fetchResellerStats = async (resellerId: string) => {
      setLoadingHistory(true);
      try {
          // Récupérer les ventes des 30 derniers jours
          const thirtyDaysAgo = new Date();
          thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

          const { data: sales, error } = await db.from('sales_history')
             .select('amount_paid, sold_at, tickets(ticket_profiles(name))')
             .eq('seller_id', resellerId)
             .gte('sold_at', thirtyDaysAgo.toISOString());

          if(error) throw error;

          // 1. Calculs globaux
          const totalRevenue30d = sales?.reduce((acc, curr) => acc + Number(curr.amount_paid), 0) || 0;
          const totalSalesCount = sales?.length || 0;
          const averageBasket = totalSalesCount > 0 ? Math.round(totalRevenue30d / totalSalesCount) : 0;

          // 2. Répartition par jour (7 derniers jours) pour le graph
          const last7Days = Array.from({length: 7}, (_, i) => {
              const d = new Date();
              d.setDate(d.getDate() - (6 - i));
              return d.toISOString().split('T')[0];
          });

          const chartData = last7Days.map(date => {
              const count = sales?.filter(s => s.sold_at.startsWith(date)).length || 0;
              return { date, count };
          });

          const maxDailySales = Math.max(...chartData.map(d => d.count), 1); // Pour l'échelle du graph

          // 3. Répartition par profil (Top produits)
          const profileStats: Record<string, number> = {};
          sales?.forEach(s => {
              const pName = (s.tickets as any)?.ticket_profiles?.name || 'Inconnu';
              profileStats[pName] = (profileStats[pName] || 0) + 1;
          });

          const topProfiles = Object.entries(profileStats)
              .map(([name, count]) => ({ name, count }))
              .sort((a, b) => b.count - a.count)
              .slice(0, 5); // Top 5

          setStatsData({
              totalRevenue30d,
              totalSalesCount,
              averageBasket,
              chartData,
              maxDailySales,
              topProfiles
          });

      } catch(err: any) {
          console.error(err);
          setToast({ type: 'error', message: "Erreur calcul statistiques." });
      } finally {
          setLoadingHistory(false);
      }
  };

  const openHistory = (reseller: User) => {
      setSelectedReseller(reseller);
      setShowHistoryModal(true);
      fetchPaymentHistoryData(reseller.id);
  };

  const openStockHistory = (reseller: User) => {
      setSelectedReseller(reseller);
      setShowStockHistoryModal(true);
      fetchStockHistoryData(reseller.id);
  };

  const openStats = (reseller: User) => {
      setSelectedReseller(reseller);
      setShowStatsModal(true);
      setStatsData(null);
      fetchResellerStats(reseller.id);
  };

  const prepareAssign = async (reseller: User) => {
    setSelectedReseller(reseller);
    if (currentUser.role === UserRole.ADMIN_GLOBAL) {
        if (reseller.tenant_id) {
            await loadProfiles(reseller.tenant_id);
        } else {
            setTicketProfiles([]); 
        }
    }
    setShowAssignModal(true);
  };

  const handlePayment = async (e: React.FormEvent) => {
    e.preventDefault(); if (!selectedReseller || !amount || processing) return;

    if ((method === 'MOMO' || method === 'OM')) {
        const rawDigits = paymentPhone.replace(/\D/g, '');
        if (!/^6\d{8}$/.test(rawDigits)) {
            setToast({ type: 'error', message: "Numéro invalide (9 chiffres commençant par 6)." });
            setTimeout(() => setToast(null), 3000);
            return;
        }
    }

    setProcessing(true);
    try {
      const rawDigits = (method === 'MOMO' || method === 'OM') ? paymentPhone.replace(/\D/g, '') : null;
      const targetTenantId = selectedReseller.tenant_id || currentUser.tenant_id;

      const { error } = await db.from('payments').insert({ 
          tenant_id: targetTenantId, 
          reseller_id: selectedReseller.id, 
          amount: Number(amount), 
          payment_method: method, 
          phone_number: rawDigits,
          created_by: currentUser.id,
          status: 'APPROVED' // Admin manual payment is auto-approved
      });

      if (error) throw error;

      const newBalance = (Number(selectedReseller.balance) || 0) + Number(amount);
      await db.from('users').update({ balance: newBalance }).eq('id', selectedReseller.id);

      setToast({ type: 'success', message: `Compte rechargé de ${Number(amount).toLocaleString()} ${currency}` }); 
      setShowPaymentModal(false); 
      setAmount('');
      setPaymentPhone('');
      setMethod('CASH');
      fetchResellers();
    } catch (err: any) { setToast({ type: 'error', message: err.message }); } finally { setProcessing(false); }
  };

  const handleAssignStock = async (e: React.FormEvent) => {
    e.preventDefault(); if (!selectedReseller || !selectedProfileId || !quantity || processing) return;
    setProcessing(true);
    try {
      const { data: availableTickets } = await db.from('tickets')
        .select('id')
        .eq('tenant_id', selectedReseller.tenant_id)
        .eq('profile_id', selectedProfileId)
        .eq('status', TicketStatus.NEUF)
        .limit(Number(quantity));

      if (!availableTickets || availableTickets.length < Number(quantity)) throw new Error("Stock insuffisant dans cette agence.");

      const ticketIds = availableTickets.map(t => t.id);
      const { error } = await db.from('tickets').update({ status: TicketStatus.ASSIGNE, assigned_to: selectedReseller.id }).in('id', ticketIds);
      if (error) throw error;

      setToast({ type: 'success', message: `${quantity} tickets ont été assignés.` }); setShowAssignModal(false); fetchResellers();
    } catch (err: any) { setToast({ type: 'error', message: err.message }); } finally { setProcessing(false); }
  };

  const filteredResellers = resellers.filter(r => r.full_name.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="space-y-8 font-sans pb-40 relative animate-in fade-in duration-500">
      {toast && (<div className={`fixed top-6 right-6 z-[100] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right border ${toast.type === 'success' ? 'bg-emerald-600 border-emerald-500' : 'bg-red-600 border-red-500'} text-white`}>{toast.type === 'success' ? <CheckCircle2 className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}<p className="font-bold text-sm tracking-tight">{toast.message}</p></div>)}

      <header className="flex flex-col xl:flex-row xl:items-end justify-between gap-6 bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500 rounded-full blur-[100px] opacity-10 -mr-20 -mt-20"></div>
        <div className="relative z-10">
            <div className="flex items-center gap-2 text-indigo-600 mb-2">
                <Wallet className="w-5 h-5" />
                <span className="text-[10px] font-black uppercase tracking-widest">Finance & Distribution</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestion Revendeurs</h1>
            <p className="text-slate-400 font-medium mt-1">Gérez les soldes, le stock et suivez les performances.</p>
        </div>

        <div className="relative z-10 flex flex-col md:flex-row gap-4 w-full xl:w-auto">
             {currentUser?.role === UserRole.ADMIN_GLOBAL && (
                 <div className="relative min-w-[200px]">
                    <Building2 className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
                    <select value={agencyFilter} onChange={(e) => setAgencyFilter(e.target.value)} className="w-full pl-10 pr-8 py-4 rounded-2xl border border-slate-100 bg-slate-50 font-bold text-slate-600 appearance-none outline-none focus:bg-white focus:ring-4 focus:ring-indigo-50 transition-all cursor-pointer text-sm"><option value="ALL">Toutes les Agences</option>{agencies.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}</select>
                    <Filter className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300 pointer-events-none" />
                 </div>
             )}

             <div className="relative group flex-1 md:w-64">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-indigo-600 transition-colors" />
                <input type="text" placeholder="Rechercher..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-12 pr-6 py-4 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-indigo-50 outline-none transition-all font-bold text-slate-700 text-sm" />
             </div>

             <div className="flex bg-slate-100 p-1.5 rounded-2xl">
                <button onClick={() => setViewMode('CARDS')} className={`p-3 rounded-xl transition-all ${viewMode === 'CARDS' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}><LayoutGrid className="w-5 h-5" /></button>
                <button onClick={() => setViewMode('TABLE')} className={`p-3 rounded-xl transition-all ${viewMode === 'TABLE' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}><List className="w-5 h-5" /></button>
             </div>
        </div>
      </header>

      {/* PENDING APPROVALS SECTION */}
      {pendingRequests.length > 0 && (
          <div className="bg-orange-50 border border-orange-100 rounded-[2.5rem] p-8 animate-in slide-in-from-top-4">
              <div className="flex items-center gap-3 mb-6">
                  <div className="bg-white p-2 rounded-xl text-orange-500 shadow-sm"><Bell className="w-5 h-5" /></div>
                  <h3 className="font-black text-slate-900 text-lg">Demandes de rechargement ({pendingRequests.length})</h3>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {pendingRequests.map(request => (
                      <div key={request.id} className="bg-white p-5 rounded-[2rem] shadow-sm border border-orange-100 flex flex-col gap-4">
                          <div className="flex justify-between items-start">
                              <div>
                                  <p className="font-black text-slate-900">{request.users?.full_name}</p>
                                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{request.payment_method}</p>
                              </div>
                              <span className="text-lg font-black text-emerald-600">{Number(request.amount).toLocaleString()}</span>
                          </div>
                          <div className="bg-slate-50 p-3 rounded-xl">
                              <p className="text-[9px] text-slate-400 uppercase font-bold mb-1">Preuve / Référence</p>
                              <p className="text-xs font-bold text-slate-700 break-all">{request.phone_number || 'Aucune référence'}</p>
                          </div>
                          <div className="grid grid-cols-2 gap-3 mt-auto">
                              <button onClick={() => handleRejectRequest(request)} className="py-2.5 rounded-xl border border-red-100 text-red-500 hover:bg-red-50 font-black text-[10px] uppercase tracking-widest transition-all">Rejeter</button>
                              <button onClick={() => handleApproveRequest(request)} className="py-2.5 rounded-xl bg-emerald-600 text-white hover:bg-emerald-700 font-black text-[10px] uppercase tracking-widest shadow-lg shadow-emerald-100 transition-all flex items-center justify-center gap-2">
                                  {processing ? <Loader2 className="w-3 h-3 animate-spin" /> : <><Check className="w-3 h-3" /> Valider</>}
                              </button>
                          </div>
                      </div>
                  ))}
              </div>
          </div>
      )}

      {loading ? (
