              totalRevenue: approvedPayments.reduce((acc, curr) => acc + Number(curr.amount), 0)
          });

      } catch (err: any) {
          console.error("Payments fetch error:", err);
          notify('error', "Erreur chargement historique paiements");
      } finally {
          setLoading(false);
      }
